#include <stdio.h>
#include <math.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long n = N;
        int k = 0;
        while((n & 1LL) == 0){ n >>= 1; k++; }
        long long m = n; // odd part, ≤ 1e5
        long long a = -1, b = -1;
        long long limit = (long long)sqrt((double)m);
        for(long long i=0;i<=limit;i++){
            long long rem = m - i*i;
            long long j = (long long)sqrt((double)rem);
            if(j*j == rem){ a = i; b = j; break; }
        }
        if(a==-1){
            printf("-1 -1\n");
            continue;
        }
        // apply factor 2^k using (a+b, |a-b|)
        for(int i=0;i<k;i++){
            long long na = a + b;
            long long nb = llabs(a - b);
            a = na; b = nb;
        }
        printf("%lld %lld\n", a, b);
    }
    return 0;
}

